    result += template.slice(lastIndex);
    for (const key of Object.keys(params)) {
        if (!consumed.has(key)) {
            throw new Error(`RedwoodSDK: Parameter "${key}" is not used by route ${template}. Check your params object for typos or remove unused parameters.`);
